class DSU(val size: Int) {
  private val parent: Array[Int] = (0 until size).map(i => i).toArray
  private val rank: Array[Int] = Array.fill(size)(0)
  private var count: Int = size

  def find(x: Int): Int = {
    if (parent(x) != x) {
      parent(x) = find(parent(x))
    }
    parent(x)
  }

  def union(x: Int, y: Int): Unit = {
    val xroot = find(x)
    val yroot = find(y)
    if (xroot == yroot) return
    if (rank(xroot) < rank(yroot)) {
      parent(xroot) = yroot
    } else {
      parent(yroot) = xroot
      if (rank(xroot) == rank(yroot)) {
        rank(xroot) += 1
      }
    }
    count -= 1
  }

  def get_count: Int = count
}

def solve(n: Long, edges: Array[Array[Long]], k: Long): Long = {
  if (edges.isEmpty) return 0
  val sortedEdges = edges.sortBy(edge => edge(2))
  val maxTime = sortedEdges.last(2)
  var low = 0L
  var high = maxTime
