def solve(n: int, edges: list[list[int]], k: int) -> int:
    edges.sort(key=lambda x: x[2])
    if not edges:
        return 0

    max_time = edges[-1][2]

    class DSU:
        def __init__(self, size):
            self.parent = list(range(size))
            self.rank = [0] * size
            self.count = size

        def find(self, x):
            if self.parent[x] != x:
                self.parent[x] = self.find(self.parent[x])
            return self.parent[x]

        def union(self, x, y):
            xroot = self.find(x)
            yroot = self.find(y)
            if xroot == yroot:
                return
            if self.rank[xroot] < self.rank[yroot]:
                self.parent[xroot] = yroot
            else:
                self.parent[yroot] = xroot
                if self.rank[xroot] == self.rank[yroot]:
                    self.rank[xroot] += 1
            self.count -= 1

        def get_count(self):
            return self.count

    low, high = 0, max_time
    answer = max_time

    while low <= high:
        mid = (low + high) // 2
        dsu = DSU(n)
        for u, v, time in edges:
            if time > mid:
                dsu.union(u, v)
        components = dsu.get_count()
        if components >= k:
            answer = mid
            high = mid - 1
        else:
            low = mid + 1

    return answer
