class DSU(val size: Int) {
    private val parent = Array.fill(size)(0)
    private val rank = Array.fill(size)(0)
    private var count = size

    def find(x: Int): Int = {
        if (parent(x) != x) {
            parent(x) = find(parent(x))
        }
        parent(x)
    }

    def union(x: Int, y: Int): Unit = {
        val xroot = find(x)
        val yroot = find(y)
        if (xroot == yroot) return
        if (rank(xroot) < rank(yroot)) {
            parent(xroot) = yroot
        } else {
            parent(yroot) = xroot
            if (rank(xroot) == rank(yroot)) {
                rank(xroot) += 1
            }
        }
        count -= 1
    }

    def get_count: Int = count
}

def solve(n: Long, edges: Array[Array[Long]], k: Long): Long = {
    val sortedEdges = edges.sortBy(edge => edge(2))
    if (sortedEdges.isEmpty) {
        return 0
    }
    val maxTime = sortedEdges.last(2)
    var low = 0L
    var high = maxTime
    var answer = maxTime
    while (low <= high) {
        val mid = (low + high) / 2
        val dsu = new DSU(n.toInt)
        for (edge <- sortedEdges) {
            val u = edge(0).toInt
            val v = edge(1).toInt
            val time = edge(2)
            if (time > mid) {
                dsu.union(u, v)
            }
        }
        val components = dsu.get_count
        if (components >= k) {
            answer = mid
            high = mid - 1
        } else {
            low = mid + 1
        }
    }
    answer
}
